class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        powers_of_5 = {bin(5**i)[2:] for i in range(16)}  # Precompute binary representations of powers of 5
        n = len(s)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0  # Base case: empty string requires 0 substrings

        for i in range(1, n + 1):
            for j in range(i):
                substr = s[j:i]
                if substr[0] == '0':  # Skip substrings with leading zeros
                    continue
                if substr in powers_of_5:
                    dp[i] = min(dp[i], dp[j] + 1)

        return dp[n] if dp[n] != float('inf') else -1
